#!/usr/bin/env bash
# eval-sweep.sh — Phase 0 gate for the IQ quantization ladder.
#
# For each candidate GGUF: perplexity on a fixed text slice (llama-perplexity)
# + the 20-prompt function battery with Paris logit margin
# (iq-ladder-battery.py). Emits one JSON report per model plus a combined
# summary. Pass/fail is a human decision at the ladder's decision point; this
# script only measures.
#
# Usage:
#   eval-sweep.sh --llama-bin-dir <dir with llama-perplexity + llama-server> \
#                 --ppl-text <file.txt> \
#                 --out-dir <reports dir> \
#                 <model1.gguf> [model2.gguf ...]
set -euo pipefail

LLAMA_BIN_DIR=""
PPL_TEXT=""
OUT_DIR=""
THREADS="${EVAL_THREADS:-0}"
MODELS=()

while [[ $# -gt 0 ]]; do
  case "$1" in
    --llama-bin-dir) LLAMA_BIN_DIR="$2"; shift 2 ;;
    --ppl-text) PPL_TEXT="$2"; shift 2 ;;
    --out-dir) OUT_DIR="$2"; shift 2 ;;
    --threads) THREADS="$2"; shift 2 ;;
    *) MODELS+=("$1"); shift ;;
  esac
done

if [[ -z "$LLAMA_BIN_DIR" || -z "$PPL_TEXT" || -z "$OUT_DIR" || ${#MODELS[@]} -eq 0 ]]; then
  echo "usage: eval-sweep.sh --llama-bin-dir DIR --ppl-text FILE --out-dir DIR model.gguf..." >&2
  exit 1
fi

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
BATTERY="$SCRIPT_DIR/iq-ladder-battery.py"
PPL_BIN="$LLAMA_BIN_DIR/llama-perplexity"
SERVER_BIN="$LLAMA_BIN_DIR/llama-server"
[[ -x "$PPL_BIN" ]] || { echo "missing $PPL_BIN" >&2; exit 1; }
[[ -x "$SERVER_BIN" ]] || { echo "missing $SERVER_BIN" >&2; exit 1; }
mkdir -p "$OUT_DIR"

THREAD_ARGS=()
if [[ "$THREADS" != "0" ]]; then THREAD_ARGS=(-t "$THREADS"); fi

SUMMARY="$OUT_DIR/summary.txt"
: > "$SUMMARY"
printf "%-40s %12s %10s %8s %14s\n" "model" "size_bytes" "ppl" "battery" "paris_margin" | tee -a "$SUMMARY"

for MODEL in "${MODELS[@]}"; do
  NAME="$(basename "$MODEL" .gguf)"
  echo "=== $NAME ===" >&2

  # 1. Perplexity. llama-perplexity prints "Final estimate: PPL = X.XXXX".
  PPL_LOG="$OUT_DIR/$NAME.ppl.log"
  # ${arr[@]+...} idiom: safe under `set -u` with empty arrays on bash 3.2 (macOS).
  "$PPL_BIN" -m "$MODEL" -f "$PPL_TEXT" -c 512 ${THREAD_ARGS[@]+"${THREAD_ARGS[@]}"} >"$PPL_LOG" 2>&1 || {
    echo "[eval] perplexity FAILED for $NAME (see $PPL_LOG)" >&2
    tail -5 "$PPL_LOG" >&2
  }
  PPL="$(grep -oE 'Final estimate: PPL = [0-9.]+' "$PPL_LOG" | grep -oE '[0-9.]+$' || echo "ERR")"

  # 2. Battery (starts/stops its own llama-server).
  BAT_JSON="$OUT_DIR/$NAME.battery.json"
  python3 "$BATTERY" --model "$MODEL" --server "$SERVER_BIN" \
    --port 8931 --threads "$THREADS" --out "$BAT_JSON" || {
    echo "[eval] battery FAILED for $NAME" >&2
  }

  BAT_SCORE="ERR"
  PARIS_MARGIN="ERR"
  if [[ -f "$BAT_JSON" ]]; then
    BAT_SCORE="$(python3 -c "import json;d=json.load(open('$BAT_JSON'));print(f\"{d['battery_pass']}/{d['battery_total']}\")")"
    PARIS_MARGIN="$(python3 -c "import json;d=json.load(open('$BAT_JSON'));m=d.get('paris_margin');print(f'{m:.4f}' if m is not None else 'n/a')")"
  fi

  SIZE="$(stat -f%z "$MODEL" 2>/dev/null || stat -c%s "$MODEL")"

  # 3. Merge per-model report.
  python3 - "$OUT_DIR/$NAME.report.json" "$MODEL" "$SIZE" "$PPL" "$BAT_JSON" <<'PYEOF'
import json, sys
out, model, size, ppl, bat_json = sys.argv[1:6]
report = {"model": model, "size_bytes": int(size), "perplexity": None if ppl == "ERR" else float(ppl)}
try:
    with open(bat_json) as f:
        report["battery"] = json.load(f)
except (OSError, json.JSONDecodeError):
    report["battery"] = None
with open(out, "w") as f:
    json.dump(report, f, indent=2)
PYEOF

  printf "%-40s %12s %10s %8s %14s\n" "$NAME" "$SIZE" "$PPL" "$BAT_SCORE" "$PARIS_MARGIN" | tee -a "$SUMMARY"
done

echo "[eval] sweep complete. summary:" >&2
cat "$SUMMARY" >&2

# Monotonicity sanity check: models are passed fine->coarse, so ppl should
# be non-decreasing down the list. A coarser rung beating a finer one by
# >10% marks a measurement/quantize flake (mistral-7b 2026-07-11: IQ2_XS
# 7.04 vs IQ3_M 14.86 with healthy batteries — impossible ordering).
python3 - "$SUMMARY" <<'PYEOF' >&2
import sys
rows = []
for line in open(sys.argv[1]).read().splitlines()[1:]:
    parts = line.split()
    if len(parts) >= 3:
        try:
            rows.append((parts[0], float(parts[2])))
        except ValueError:
            pass
for i in range(2, len(rows)):  # skip baseline->first-rung transition
    name_prev, ppl_prev = rows[i - 1]
    name, ppl = rows[i]
    if ppl < ppl_prev * 0.9:
        print(f"[eval] ANOMALY: {name} (ppl {ppl}) beats finer rung "
              f"{name_prev} (ppl {ppl_prev}) by >10% — non-monotone ladder; "
              f"DO NOT TRUST without a rerun (see IQ_ROLLOUT_LOG 2026-07-11)")
PYEOF
